  1→/**
  2→ * PianoQuest Live — Express + WebSocket server with Gemini Live API.
  3→ *
  4→ * Uses @google/genai SDK live.connect() for Gemini Live sessions.
  5→ */
  6→
  7→import express from "express";
  8→import { createServer } from "http";
  9→import path from "path";
 10→import fs from "fs";
 11→import { WebSocketServer, WebSocket } from "ws";
 12→import type { IncomingMessage } from "http";
 13→import { GoogleGenAI, Modality, type Session } from "@google/genai";
 14→import {
 15→  LIVE_MODEL,
 16→  STORYTELLER_INSTRUCTION,
 17→  buildToolDeclarations,
 18→  executeToolLocally,
 19→  toolCallToVisualEvent,
 20→} from "./agent.js";
 21→
 22→const APP_NAME = "pianoquest";
 23→const STATIC_DIR = path.join(__dirname, "..", "..", "static");
 24→const SHEETS_DIR = path.join(__dirname, "..", "..", "sheets");
 25→
 26→
 27→const NOTE_NAMES = ["C", "C#", "D", "D#", "E", "F", "F#", "G", "G#", "A", "A#", "B"];
 28→
 29→function midiNoteName(note: number): string {
 30→  const octave = Math.floor(note / 12) - 1;
 31→  return `${NOTE_NAMES[note % 12]}${octave}`;
 32→}
 33→
 34→function describeMidiSnapshot(
 35→  msg: Record<string, unknown>,
 36→): string | null {
 37→  const recentNotes = (msg.recent_notes as Array<Record<string, unknown>>) ?? [];
 38→  const activeNotes = (msg.active_notes as Array<Record<string, unknown>>) ?? [];
 39→  const detectedTechniques = (msg.detected_techniques as unknown[]) ?? [];
 40→  const pedalDown = Boolean(msg.pedal_down);
 41→  const bpm = msg.bpm as number | undefined;
 42→  const score = msg.score as number | undefined;
 43→
 44→  const noteBits: string[] = [];
 45→  for (const item of recentNotes.slice(0, 8)) {
 46→    const note = item.note as number | undefined;
 47→    const velocity = item.velocity as number | undefined;
 48→    if (typeof note === "number") {
 49→      noteBits.push(
 50→        typeof velocity === "number"
 51→          ? `${midiNoteName(note)}@${velocity}`
 52→          : midiNoteName(note)
 53→      );
 54→    }
 55→  }
 56→
 57→  const activeBits: string[] = [];
 58→  for (const item of activeNotes.slice(0, 8)) {
 59→    const note = item.note as number | undefined;
 60→    const velocity = item.velocity as number | undefined;
 61→    if (typeof note === "number") {
 62→      activeBits.push(
 63→        typeof velocity === "number"
 64→          ? `${midiNoteName(note)}@${velocity}`
 65→          : midiNoteName(note)
 66→      );
 67→    }
 68→  }
 69→
 70→  const hasPerformanceSignal = recentNotes.length > 0 || activeNotes.length > 0 || pedalDown;
 71→  if (!hasPerformanceSignal) return null;
 72→
 73→  const details: string[] = [];
 74→  if (noteBits.length > 0) details.push("recent notes: " + noteBits.join(", "));
 75→  if (activeBits.length > 0) details.push("currently held: " + activeBits.join(", "));
 76→  details.push(pedalDown ? "sustain pedal is down" : "sustain pedal is up");
 77→  if (bpm) details.push(`target tempo ${bpm} BPM`);
 78→  if (score !== undefined) details.push(`current technique score ${score}`);
 79→  if (detectedTechniques.length > 0) {
 80→    details.push(
 81→      "detected techniques: " + detectedTechniques.slice(0, 6).map(String).join(", ")
 82→    );
 83→  }
 84→
 85→  if (details.length === 0) return null;
 86→
 87→  return (
 88→    "MIDI performance update from the digital piano. " +
 89→    details.join(". ") +
 90→    ". Use this instead of piano microphone audio for note, timing, and dynamics analysis."
 91→  );
 92→}
 93→
 94→// =========================================================================
 95→// Spectator broadcasting — spectators receive all output but send nothing
 96→// =========================================================================
 97→
 98→const spectators = new Set<WebSocket>();
 99→
100→function broadcastSpectators(data: Buffer | string, binary = false) {
101→  for (const s of spectators) {
102→    if (s.readyState === WebSocket.OPEN) {
103→      try { s.send(data, { binary }); } catch {}
104→    }
105→  }
106→}
107→
108→// =========================================================================
109→// Device management types
110→// =========================================================================
111→
112→interface DeviceRoles {
113→  mic: boolean;
114→  midi: boolean;
115→}
116→
117→interface Device {
118→  id: string;
119→  ws: WebSocket;
120→  name: string;
121→  deviceType: "desktop" | "tablet" | "phone" | "unknown";
122→  isPrimary: boolean;
123→  roles: DeviceRoles;
124→  connectedAt: number;
125→}
126→
127→interface RoomSession {
128→  sendRealtimeInput: (input: any) => void;
129→  sendClientContent: (content: any) => void;
130→  primaryWs: WebSocket;
131→  /** All devices in this room */
132→  devices: Map<string, Device>;
133→  /** Accumulated MIDI notes for periodic Gemini snapshots */
134→  midiBuffer: Array<{ note: number; velocity: number; event: string; timestampMs: number }>;
135→  midiFlushTimer: ReturnType<typeof setTimeout> | null;
136→}
137→
138→const rooms = new Map<string, RoomSession>();
139→
140→function generateRoomCode(): string {
141→  const chars = "REDACTED";
142→  let code = "";
143→  const arr = new Uint8Array(4);
144→  require("crypto").randomFillSync(arr);
145→  for (let i = 0; i < 4; i++) {
146→    code += chars[arr[i] % chars.length];
147→  }
148→  return code;
149→}
150→
151→function randomHex(bytes: number): string {
152→  const arr = new Uint8Array(bytes);
153→  require("crypto").randomFillSync(arr);
154→  return Buffer.from(arr).toString("hex");
155→}
156→
157→// =========================================================================
158→// Device detection from User-Agent
159→// =========================================================================
160→
161→function detectDeviceType(req: IncomingMessage): "desktop" | "tablet" | "phone" | "unknown" {
162→  const ua = (req.headers["user-agent"] || "").toLowerCase();
163→  if (ua.includes("ipad") || (ua.includes("android") && !ua.includes("mobile"))) return "tablet";
164→  if (ua.includes("iphone") || ua.includes("android")) return "phone";
165→  if (ua.includes("windows") || ua.includes("macintosh") || ua.includes("linux")) return "desktop";
166→  return "unknown";
167→}
168→
169→function deviceTypeIcon(type: string): string {
170→  switch (type) {
171→    case "desktop": return "💻";
172→    case "tablet": return "📱";
173→    case "phone": return "📷";
174→    default: return "🔲";
175→  }
176→}
177→
178→function deviceTypeName(type: string): string {
179→  switch (type) {
180→    case "desktop": return "Desktop";
181→    case "tablet": return "Tablet";
182→    case "phone": return "Phone";
183→    default: return "Device";
184→  }
185→}
186→
187→// =========================================================================
188→// Room broadcasting — send to all devices in a room + spectators
189→// =========================================================================
190→
191→function broadcastToRoom(room: RoomSession, data: Buffer | string, binary = false) {
192→  for (const device of room.devices.values()) {
193→    if (device.ws.readyState === WebSocket.OPEN) {
194→      try { device.ws.send(data, { binary }); } catch {}
195→    }
196→  }
197→  broadcastSpectators(data, binary);
198→}
199→
200→function sendDeviceList(room: RoomSession) {
201→  const list = Array.from(room.devices.values()).map((d) => ({
202→    id: d.id,
203→    name: d.name,
204→    deviceType: d.deviceType,
205→    isPrimary: d.isPrimary,
206→    roles: { ...d.roles },
207→    connectedAt: d.connectedAt,
208→  }));
209→  const msg = JSON.stringify({ type: "device_list", devices: list });
210→  // Send to all devices so everyone can see the roster
211→  for (const device of room.devices.values()) {
212→    if (device.ws.readyState === WebSocket.OPEN) {
213→      try { device.ws.send(msg); } catch {}
214→    }
215→  }
216→}
217→
218→function setDeviceRole(
219→  room: RoomSession,
220→  deviceId: string,
221→  role: keyof DeviceRoles,
222→  enabled: boolean
223→) {
224→  const device = room.devices.get(deviceId);
225→  if (!device) return;
226→
227→  if (enabled) {
228→    // Exclusive: disable this role on all other devices
229→    for (const d of room.devices.values()) {
230→      if (d.id !== deviceId && d.roles[role]) {
231→        d.roles[role] = false;
232→        // Notify the device that lost the role
233→        if (d.ws.readyState === WebSocket.OPEN) {
234→          try {
235→            d.ws.send(JSON.stringify({
236→              type: "role_assigned",
237→              roles: { ...d.roles },
238→            }));
239→          } catch {}
240→        }
241→      }
242→    }
243→  }
244→
245→  device.roles[role] = enabled;
246→
247→  // Notify the device that got/lost the role
248→  if (device.ws.readyState === WebSocket.OPEN) {
249→    try {
250→      device.ws.send(JSON.stringify({
251→        type: "role_assigned",
252→        roles: { ...device.roles },
253→      }));
254→    } catch {}
255→  }
256→
257→  // Broadcast updated device list
258→  sendDeviceList(room);
259→}
260→
261→// =========================================================================
262→// Express + WebSocket server
263→// =========================================================================
264→
265→export function createApp() {
266→  const app = express();
267→  const server = createServer(app);
268→  const wssDialog = new WebSocketServer({ noServer: true });
269→  const wssSpectator = new WebSocketServer({ noServer: true });
270→  const wssMidi = new WebSocketServer({ noServer: true });
271→  const wssSession = new WebSocketServer({ noServer: true });
272→
273→  app.get("/health", (_req, res) => {
274→    res.json({
275→      status: "ok",
276→      service: APP_NAME,
277→      modes: ["storyteller"],
278→      spectators: spectators.size,
279→      rooms: rooms.size,
280→    });
281→  });
282→
283→  app.get("/", (_req, res) => {
284→    res.sendFile(path.join(STATIC_DIR, "index.html"));
285→  });
286→
287→  app.use("/static", express.static(STATIC_DIR));
288→  app.use("/sheets", express.static(SHEETS_DIR));
289→
290→  // List sheet music files as a tree
291→  app.get("/api/sheets", (_req, res) => {
292→    function walkDir(dir: string, prefix: string): any[] {
293→      const entries: any[] = [];
294→      if (!fs.existsSync(dir)) return entries;
295→      for (const name of fs.readdirSync(dir).sort()) {
296→        const full = path.join(dir, name);
297→        const rel = prefix ? `${prefix}/${name}` : name;
298→        const stat = fs.statSync(full);
299→        if (stat.isDirectory()) {
300→          entries.push({ name, path: rel, type: "folder", children: walkDir(full, rel) });
301→        } else if (name.endsWith(".json")) {
302→          entries.push({ name: name.replace(".json", ""), path: rel, type: "file" });
303→        }
304→      }
305→      return entries;
306→    }
307→    res.json(walkDir(SHEETS_DIR, ""));
308→  });
309→
310→  server.on("upgrade", (request: IncomingMessage, socket, head) => {
311→    const url = new URL(request.url ?? "/", `http://${request.headers.host}`);
312→    if (url.pathname === "/ws/session") {
313→      wssSession.handleUpgrade(request, socket, head, (ws) => {
314→        (ws as any)._req = request;
315→        (ws as any)._room = url.searchParams.get("room") ?? "";
316→        (ws as any)._roleHint = url.searchParams.get("role") ?? "";
317→        wssSession.emit("connection", ws, request);
318→      });
319→    } else if (url.pathname === "/ws/dialog") {
320→      wssDialog.handleUpgrade(request, socket, head, (ws) => {
321→        wssDialog.emit("connection", ws, request);
322→      });
323→    } else if (url.pathname === "/ws/spectator") {
324→      wssSpectator.handleUpgrade(request, socket, head, (ws) => {
325→        wssSpectator.emit("connection", ws, request);
326→      });
327→    } else if (url.pathname === "/ws/midi") {
328→      const room = url.searchParams.get("room") ?? "";
329→      wssMidi.handleUpgrade(request, socket, head, (ws) => {
330→        (ws as any)._room = room;
331→        wssMidi.emit("connection", ws, request);
332→      });
333→    } else {
334→      socket.destroy();
335→    }
336→  });
337→
338→  // -----------------------------------------------------------------
339→  // /ws/session — Unified device management endpoint
340→  // -----------------------------------------------------------------
341→
342→  wssSession.on("connection", (ws: WebSocket) => {
343→    const req = (ws as any)._req as IncomingMessage;
344→    const roomCode = (ws as any)._room as string;
345→    const roleHint = (ws as any)._roleHint as string;
346→    const devType = detectDeviceType(req);
347→
348→    if (!roomCode) {
349→      // No room code — this is a new primary device
350→      handlePrimaryWebSocket(ws, req);
351→    } else {
352→      // Room code provided — join as secondary
353→      const room = rooms.get(roomCode);
354→      if (!room) {
355→        console.log(`[${APP_NAME}] Session rejected — room "${roomCode}" not found`);
356→        ws.send(JSON.stringify({ type: "error", message: `Room "${roomCode}" not found` }));
357→        ws.close();
358→        return;
359→      }
360→      handleSecondaryWebSocket(ws, room, roomCode, devType, roleHint);
361→    }
362→  });
363→
364→  // -----------------------------------------------------------------
365→  // /ws/dialog — Legacy primary endpoint (backwards compat)
366→  // -----------------------------------------------------------------
367→
368→  wssDialog.on("connection", (ws: WebSocket, req: IncomingMessage) => {
369→    handlePrimaryWebSocket(ws, req);
370→  });
371→
372→  wssSpectator.on("connection", (ws: WebSocket) => {
373→    spectators.add(ws);
374→    console.log(`[${APP_NAME}] Spectator connected (total: ${spectators.size})`);
375→
376→    // Send immediate status so bridge knows connection is live
377→    const activeRoom = Array.from(rooms.values())[0];
378→    ws.send(JSON.stringify({
379→      type: "spectator_status",
380→      connected: true,
381→      spectators: spectators.size,
382→      activeSession: !!activeRoom,
383→      room: activeRoom ? Array.from(rooms.keys())[0] : null,
384→    }));
385→
386→    // Keepalive ping every 20s to prevent Cloud Run timeout
387→    let alive = true;
388→    const pingInterval = setInterval(() => {
389→      if (ws.readyState !== WebSocket.OPEN) {
390→        clearInterval(pingInterval);
391→        return;
392→      }
393→      if (!alive) {
394→        // Missed pong — connection dead
395→        ws.terminate();
396→        return;
397→      }
398→      alive = false;
399→      ws.ping();
400→    }, 20000);
401→
402→    ws.on("pong", () => { alive = true; });
403→    ws.on("close", () => {
404→      clearInterval(pingInterval);
405→      spectators.delete(ws);
406→      console.log(`[${APP_NAME}] Spectator disconnected (total: ${spectators.size})`);
407→    });
408→    ws.on("error", () => {
409→      clearInterval(pingInterval);
410→      spectators.delete(ws);
411→    });
412→  });
413→
414→  // -----------------------------------------------------------------
415→  // /ws/midi — Ubuntu bridge forwards MIDI events to Gemini + iPad
416→  // -----------------------------------------------------------------
417→
418→  function flushMidiToGemini(roomSession: RoomSession) {
419→    if (roomSession.midiBuffer.length === 0) return;
420→
421→    const recentNotes = roomSession.midiBuffer
422→      .filter((m) => m.event === "noteOn")
423→      .slice(-8)
424→      .map((m) => ({ note: m.note, velocity: m.velocity }));
425→
426→    const activeNotes: Array<{ note: number; velocity: number }> = [];
427→    const noteOnMap = new Map<number, number>();
428→    for (const m of roomSession.midiBuffer) {
429→      if (m.event === "noteOn") {
430→        noteOnMap.set(m.note, m.velocity);
431→      } else if (m.event === "noteOff") {
432→        noteOnMap.delete(m.note);
433→      }
434→    }
435→    for (const [note, velocity] of noteOnMap) {
436→      activeNotes.push({ note, velocity });
437→    }
438→
439→    const summary = describeMidiSnapshot(
440→      { recent_notes: recentNotes, active_notes: activeNotes, pedal_down: false },
441→    );
442→
443→    if (summary) {
444→      roomSession.sendClientContent({
445→        turns: [{ role: "user", parts: [{ text: summary }] }],
446→        turnComplete: true,
447→      });
448→    }
449→
450→    roomSession.midiBuffer = [];
451→  }
452→
453→  wssMidi.on("connection", (ws: WebSocket) => {
454→    const room = (ws as any)._room as string;
455→    const roomSession = rooms.get(room);
456→    if (!roomSession) {
457→      console.log(`[${APP_NAME}] MIDI rejected — room "${room}" not found`);
458→      ws.send(JSON.stringify({ type: "error", message: `Room "${room}" not found` }));
459→      ws.close();
460→      return;
461→    }
462→
463→    console.log(`[${APP_NAME}] MIDI bridge connected to room "${room}"`);
464→    ws.send(JSON.stringify({ type: "midi_connected", room }));
465→
466→    ws.on("message", (data: Buffer | string) => {
467→      if (typeof data !== "string") return;
468→      try {
469→        const msg = JSON.parse(data);
470→        if (msg.type !== "midi") return;
471→
472→        // Forward raw MIDI event to all room devices for waterfall rendering
473→        broadcastToRoom(roomSession, JSON.stringify(msg));
474→
475→        // Buffer for Gemini (flush every 2 seconds)
476→        if (msg.event === "noteOn" || msg.event === "noteOff") {
477→          roomSession.midiBuffer.push({
478→            note: msg.note ?? 0,
479→            velocity: msg.velocity ?? 0,
480→            event: msg.event,
481→            timestampMs: msg.timestampMs ?? Date.now(),
482→          });
483→
484→          if (!roomSession.midiFlushTimer) {
485→            roomSession.midiFlushTimer = setTimeout(() => {
486→              roomSession.midiFlushTimer = null;
487→              flushMidiToGemini(roomSession);
488→            }, 2000);
489→          }
490→        }
491→      } catch {}
492→    });
493→
494→    ws.on("close", () => {
495→      console.log(`[${APP_NAME}] MIDI bridge disconnected from room "${room}"`);
496→      if (roomSession.midiFlushTimer) {
497→        clearTimeout(roomSession.midiFlushTimer);
498→        roomSession.midiFlushTimer = null;
499→        flushMidiToGemini(roomSession);
500→      }
501→    });
502→  });
503→
504→  return server;
505→}
506→
507→// =========================================================================
508→// Async WebSocket message generator
509→// =========================================================================
510→
511→async function* wsMessages(
512→  ws: WebSocket
513→): AsyncGenerator<Buffer | string, void, undefined> {
514→  const queue: (Buffer | string)[] = [];
515→  let resolve: (() => void) | null = null;
516→  let done = false;
517→
518→  ws.on("message", (data: Buffer | string, isBinary: boolean) => {
519→    // ws library delivers ALL messages as Buffer; use isBinary to distinguish
520→    const item = isBinary ? data : data.toString();
521→    queue.push(item);
522→    if (resolve) {
523→      resolve();
524→      resolve = null;
525→    }
526→  });
527→
528→  ws.on("close", () => {
529→    done = true;
530→    if (resolve) {
531→      resolve();
532→      resolve = null;
533→    }
534→  });
535→
536→  ws.on("error", () => {
537→    done = true;
538→    if (resolve) {
539→      resolve();
540→      resolve = null;
541→    }
542→  });
543→
544→  while (true) {
545→    if (queue.length > 0) {
546→      yield queue.shift()!;
547→    } else if (done) {
548→      return;
549→    } else {
550→      await new Promise<void>((r) => {
551→        resolve = r;
552→      });
553→    }
554→  }
555→}
556→
557→// =========================================================================
558→// Secondary device handler — joins an existing room
559→// =========================================================================
560→
561→async function handleSecondaryWebSocket(
562→  ws: WebSocket,
563→  room: RoomSession,
564→  roomCode: string,
565→  devType: "desktop" | "tablet" | "phone" | "unknown",
566→  roleHint: string
567→) {
568→  const deviceId = randomHex(4);
569→  const device: Device = {
570→    id: deviceId,
571→    ws,
572→    name: deviceTypeName(devType),
573→    deviceType: devType,
574→    isPrimary: false,
575→    roles: { mic: false, midi: false },
576→    connectedAt: Date.now(),
577→  };
578→
579→  room.devices.set(deviceId, device);
580→  console.log(`[${APP_NAME}] Secondary device ${deviceId} (${devType}) joined room "${roomCode}"`);
581→
582→  // Send identity to the secondary device
583→  ws.send(JSON.stringify({
584→    type: "you_are_secondary",
585→    room: roomCode,
586→    deviceId,
587→    deviceType: devType,
588→  }));
589→
590→  // If role hint provided, auto-assign that role
591→  if (roleHint === "mic" || roleHint === "midi") {
592→    setDeviceRole(room, deviceId, roleHint as keyof DeviceRoles, true);
593→  }
594→
595→  // Broadcast updated device list
596→  sendDeviceList(room);
597→
598→  // Handle incoming messages from secondary
599→  try {
600→    for await (const rawMsg of wsMessages(ws)) {
601→      // Binary = PCM audio (only if this device has mic role)
602→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
603→        if (!device.roles.mic) continue;
604→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
605→        room.sendRealtimeInput({
606→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
607→        });
608→      } else if (typeof rawMsg === "string") {
609→        const msg = JSON.parse(rawMsg);
610→        const msgType = msg.type;
611→
612→        if (msgType === "midi_snapshot" && device.roles.midi) {
613→          const summary = describeMidiSnapshot(msg);
614→          if (summary) {
615→            room.sendClientContent({
616→              turns: [{ role: "user", parts: [{ text: summary }] }],
617→              turnComplete: true,
618→            });
619→          }
620→        } else if (msgType === "midi_event" && device.roles.midi) {
621→          // Forward raw MIDI to all room devices for visualization
622→          broadcastToRoom(room, JSON.stringify(msg));
623→        } else if (msgType === "text") {
624→          room.sendClientContent({
625→            turns: [{ role: "user", parts: [{ text: msg.content as string }] }],
626→            turnComplete: true,
627→          });
628→        } else if (msgType === "user_speech_transcript") {
629→          // Browser SpeechRecognition transcript — broadcast to all devices
630→          const text = (msg.text as string || "").trim();
631→          if (text) {
632→            broadcastToRoom(room, JSON.stringify({ type: "input_transcript", text }));
633→          }
634→        } else if (msgType === "device_info") {
635→          // Device sends its name
636→          if (msg.name) device.name = String(msg.name).slice(0, 32);
637→          sendDeviceList(room);
638→        } else if (msgType === "close") {
639→          break;
640→        }
641→      }
642→    }
643→  } catch (e: any) {
644→    console.log(`[${APP_NAME}] Secondary ${deviceId} error:`, e?.message);
645→  } finally {
646→    room.devices.delete(deviceId);
647→    console.log(`[${APP_NAME}] Secondary device ${deviceId} disconnected from room "${roomCode}"`);
648→    sendDeviceList(room);
649→    try { ws.close(); } catch {}
650→  }
651→}
652→
653→// =========================================================================
654→// Primary WebSocket handler — creates Gemini Live session
655→// =========================================================================
656→
657→async function handlePrimaryWebSocket(ws: WebSocket, req: IncomingMessage) {
658→  const apiKey = process.env.GOOGLE_API_KEY ?? process.env.GEMINI_API_KEY;
659→  if (!apiKey) {
660→    ws.send(JSON.stringify({ type: "error", message: "No API key configured" }));
661→    ws.close();
662→    return;
663→  }
664→
665→  const sessionId = randomHex(4);
666→  const roomCode = generateRoomCode();
667→  let closed = false;
668→
669→  // Transcription buffers
670→  let bufInput = "";
671→  let bufOutput = "";
672→
673→  // Device registration for primary
674→  const devType = detectDeviceType(req);
675→  const primaryDeviceId = randomHex(4);
676→  const primaryDevice: Device = {
677→    id: primaryDeviceId,
678→    ws,
679→    name: deviceTypeName(devType) + " (Primary)",
680→    deviceType: devType,
681→    isPrimary: true,
682→    roles: { mic: true, midi: true },
683→    connectedAt: Date.now(),
684→  };
685→
686→  console.log(`[${APP_NAME}] Primary connected: ${sessionId}, room: ${roomCode}, device: ${primaryDeviceId}`);
687→
688→  // ---------------------------------------------------------------------------
689→  // Gemini Live API via @google/genai SDK
690→  // ---------------------------------------------------------------------------
691→  const client = new GoogleGenAI({ apiKey });
692→  let session: Session;
693→  let roomSession: RoomSession | null = null;
694→  let audioMsgCount = 0;
695→
696→  const sendAll = (data: Buffer | string, binary = false) => {
697→    if (roomSession) broadcastToRoom(roomSession, data, binary);
698→  };
699→
700→  try {
701→    session = await client.live.connect({
702→      model: LIVE_MODEL,
703→      config: {
704→        responseModalities: [Modality.AUDIO],
705→        systemInstruction: STORYTELLER_INSTRUCTION,
706→        speechConfig: {
707→          voiceConfig: {
708→            prebuiltVoiceConfig: { voiceName: "Puck" },
709→          },
710→        },
711→        outputAudioTranscription: {},
712→        realtimeInputConfig: {
713→          automaticActivityDetection: {
714→            disabled: false,
715→          },
716→        },
717→        tools: buildToolDeclarations() as any,
718→      },
719→      callbacks: {
720→        onopen: () => {
721→          console.log(`[${APP_NAME}] Gemini Live connected: ${sessionId}`);
722→          roomSession = {
723→            sendRealtimeInput: (input: any) => session.sendRealtimeInput(input),
724→            sendClientContent: (content: any) => session.sendClientContent(content),
725→            primaryWs: ws,
726→            devices: new Map(),
727→            midiBuffer: [],
728→            midiFlushTimer: null,
729→          };
730→          roomSession.devices.set(primaryDeviceId, primaryDevice);
731→          rooms.set(roomCode, roomSession);
732→
733→          ws.send(JSON.stringify({ type: "you_are_primary", room: roomCode, deviceId: primaryDeviceId }));
734→          ws.send(JSON.stringify({ type: "room_code", room: roomCode }));
735→          sendDeviceList(roomSession);
736→
737→          // No greeting — Gemini stays silent until user speaks
738→        },
739→        onerror: (e: unknown) => {
740→          console.error(`[${APP_NAME}] Gemini error: ${sessionId}`, e);
741→          try { ws.send(JSON.stringify({ type: "gemini_error", error: String(e) })); } catch {}
742→        },
743→        onclose: () => {
744→          console.error(`[${APP_NAME}] *** Gemini closed: session=${sessionId}`);
745→          closed = true;
746→          try { ws.send(JSON.stringify({ type: "gemini_error", code: 1000, reason: "Session ended" })); } catch {}
747→          try { ws.close(); } catch {}
748→        },
749→        onmessage: (msg: unknown) => {
750→          if (closed || !roomSession) return;
751→          const message = msg as Record<string, unknown>;
752→          const msgKeys = Object.keys(message);
753→
754→          // Log non-audio messages for debugging
755→          if (msgKeys.includes("setupComplete")) {
756→            console.log(`[${APP_NAME}] ${sessionId} setupComplete`);
757→            return;
758→          }
759→
760→          const serverContent = message.serverContent as Record<string, unknown> | undefined;
761→          if (serverContent) {
762→            const modelTurn = serverContent.modelTurn as Record<string, unknown> | undefined;
763→            if (modelTurn?.parts) {
764→              const parts = modelTurn.parts as Array<Record<string, unknown>>;
765→              for (const part of parts) {
766→                const inlineData = part.inlineData as Record<string, unknown> | undefined;
767→                if (inlineData?.data) {
768→                  audioMsgCount++;
769→                  if (audioMsgCount <= 3) console.log(`[${APP_NAME}] ${sessionId} audio chunk #${audioMsgCount}`);
770→                  sendAll(Buffer.from(inlineData.data as string, "base64"), true);
771→                }
772→                // Tool calls
773→                const functionCall = part.functionCall as Record<string, unknown> | undefined;
774→                if (functionCall) {
775→                  const name = functionCall.name as string;
776→                  const args = (functionCall.args as Record<string, unknown>) || {};
777→                  const visualEvent = toolCallToVisualEvent(name, args);
778→                  if (visualEvent) sendAll(JSON.stringify(visualEvent));
779→                  const result = executeToolLocally(name, args);
780→                  const id = functionCall.id as string;
781→                  session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
782→                  console.log(`[${APP_NAME}] ${sessionId} tool: ${name}`);
783→                }
784→              }
785→            }
786→
787→            // Transcription
788→            const outputTranscription = serverContent.outputTranscription as Record<string, unknown> | undefined;
789→            if (outputTranscription?.text) {
790→              const text = (outputTranscription.text as string).trim();
791→              if (text) {
792→                bufOutput += (bufOutput ? " " : "") + text;
793→                console.log(`[${APP_NAME}] ${sessionId} OUT: ${text}`);
794→              }
795→            }
796→
797→            // Turn complete
798→            if (serverContent.turnComplete) {
799→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
800→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
801→              sendAll(JSON.stringify({ type: "turn_complete" }));
802→              console.log(`[${APP_NAME}] ${sessionId} turnComplete (audioChunks=${audioMsgCount})`);
803→            }
804→
805→            // Interrupted
806→            if (serverContent.interrupted) {
807→              if (bufInput) { sendAll(JSON.stringify({ type: "input_transcript", text: bufInput })); bufInput = ""; }
808→              if (bufOutput) { sendAll(JSON.stringify({ type: "output_transcript", text: bufOutput })); bufOutput = ""; }
809→              sendAll(JSON.stringify({ type: "interrupted" }));
810→              console.log(`[${APP_NAME}] ${sessionId} interrupted`);
811→            }
812→          }
813→
814→          // toolCallCancellation
815→          const toolCall = message.toolCall as Record<string, unknown> | undefined;
816→          if (toolCall?.functionCalls) {
817→            const functionCalls = toolCall.functionCalls as Array<Record<string, unknown>>;
818→            for (const fc of functionCalls) {
819→              const name = fc.name as string;
820→              const id = fc.id as string;
821→              const args = (fc.args as Record<string, unknown>) || {};
822→              const visualEvent = toolCallToVisualEvent(name, args);
823→              if (visualEvent) sendAll(JSON.stringify(visualEvent));
824→              const result = executeToolLocally(name, args);
825→              session.sendToolResponse({ functionResponses: [{ id, name, response: result }] });
826→              console.log(`[${APP_NAME}] ${sessionId} toolCall: ${name}`);
827→            }
828→          }
829→        },
830→      },
831→    });
832→  } catch (err) {
833→    console.error(`[${APP_NAME}] Failed to connect Gemini Live:`, err);
834→    ws.send(JSON.stringify({ type: "error", message: "Failed to connect to Gemini" }));
835→    ws.close(1011, "Failed to connect to Gemini");
836→    return;
837→  }
838→
839→  console.log(`[${APP_NAME}] Gemini session ready: ${sessionId}, room: ${roomCode}`);
840→
841→  // ---------------------------------------------------------------------------
842→  // Receive from primary client, forward to Gemini
843→  // ---------------------------------------------------------------------------
844→  try {
845→    for await (const rawMsg of wsMessages(ws)) {
846→      if (closed) break;
847→
848→      if (rawMsg instanceof Buffer || rawMsg instanceof ArrayBuffer) {
849→        if (!primaryDevice.roles.mic) continue;
850→        const data = rawMsg instanceof ArrayBuffer ? new Uint8Array(rawMsg) : rawMsg;
851→        session.sendRealtimeInput({
852→          audio: { data: Buffer.from(data).toString("base64"), mimeType: "audio/pcm;rate=16000" },
853→        });
854→      } else if (typeof rawMsg === "string") {
855→        const msg = JSON.parse(rawMsg);
856→        const msgType = msg.type;
857→
858→
859→        if (msgType === "text") {
860→          session.sendClientContent({
861→            turns: [{ role: "user", parts: [{ text: msg.content }] }],
862→            turnComplete: true,
863→          });
864→        } else if (msgType === "midi_snapshot") {
865→          // MIDI snapshots are for local visualization only — don't send to Gemini.
866→          // Gemini hears the piano audio directly and responds to voice, not text summaries.
867→        } else if (msgType === "user_speech_transcript") {
868→          // Browser SpeechRecognition transcript — broadcast to all devices
869→          const text = (msg.text as string || "").trim();
870→          if (text && roomSession) {
871→            broadcastToRoom(roomSession, JSON.stringify({ type: "input_transcript", text }));
872→          }
873→        } else if (msgType === "set_mode") {
874→          // Single agent — mode is always storyteller
875→        } else if (msgType === "midi_event") {
876→          // Broadcast MIDI events to all room devices + spectators for visualization
877→          if (roomSession) {
878→            console.log(`[${APP_NAME}] midi_event broadcast to room + ${spectators.size} spectators`);
879→            broadcastToRoom(roomSession, JSON.stringify(msg));
880→          } else {
881→            console.log(`[${APP_NAME}] midi_event broadcast to ${spectators.size} spectators (no room)`);
882→            broadcastSpectators(JSON.stringify(msg));
883→          }
884→        } else if (msgType === "set_device_role") {
885→          const { deviceId, role, enabled } = msg;
886→          if (roomSession && (role === "mic" || role === "midi")) {
887→            setDeviceRole(roomSession as RoomSession, deviceId, role, Boolean(enabled));
888→            console.log(`[${APP_NAME}] Role ${role}=${enabled} on device ${deviceId}`);
889→          }
890→        } else if (msgType === "close") {
891→          break;
892→        }
893→      }
894→    }
895→  } catch (e: any) {
896→    if (!closed) console.log(`[${APP_NAME}] receive error:`, e?.message);
897→  }
898→
899→  closed = true;
900→  try { session.close(); } catch {}
901→
902→  // Cleanup
903→  const rs = rooms.get(roomCode);
904→  if (rs?.midiFlushTimer) clearTimeout(rs.midiFlushTimer);
905→  if (rs) {
906→    for (const d of rs.devices.values()) {
907→      if (!d.isPrimary && d.ws.readyState === WebSocket.OPEN) {
908→        try {
909→          d.ws.send(JSON.stringify({ type: "room_closed" }));
910→          d.ws.close();
911→        } catch {}
912→      }
913→    }
914→  }
915→  rooms.delete(roomCode);
916→  console.log(`[${APP_NAME}] Primary disconnected: ${sessionId}, room ${roomCode} removed`);
917→  try { ws.close(); } catch {}
918→}
919→

