749→function detectTechniques() {
750→  var notes = recentMidiNotes.slice(-12).map(function(item) { return item.note; });
751→  var labels = [];
752→  if (notes.length < 2) return labels;
753→
754→  var ascendingRun = 1;
755→  var descendingRun = 1;
756→  var repeatedRun = 1;
757→  var arpeggioRun = 1;
758→
759→  function pushUnique(label) {
760→    if (labels.indexOf(label) === -1) labels.push(label);
761→  }
762→
763→  for (var i = 1; i < notes.length; i++) {
764→    var diff = notes[i] - notes[i - 1];
765→    var absDiff = Math.abs(diff);
766→
767→    if (diff === 1 || diff === 2) ascendingRun += 1;
768→    else ascendingRun = 1;
769→
770→    if (diff === -1 || diff === -2) descendingRun += 1;
771→    else descendingRun = 1;
772→
773→    if (ascendingRun >= 4) pushUnique('scale_run_ascending');
774→    if (descendingRun >= 4) pushUnique('scale_run_descending');
775→
776→    if (notes[i] === notes[i - 1]) repeatedRun += 1;
777→    else repeatedRun = 1;
778→
779→    if (repeatedRun >= 3) {
780→      pushUnique('repeated_note(' + noteName(notes[i]) + 'x' + repeatedRun + ')');
781→    }
782→
783→    if (absDiff === 3 || absDiff === 4) arpeggioRun += 1;
784→    else arpeggioRun = 1;
785→
786→    if (arpeggioRun >= 3) pushUnique('arpeggio');
787→    if (absDiff > 7) pushUnique('wide_leap');
788→  }
789→
790→  return labels;
791→}
