1003→async function refreshMidiInputs() {
1004→  var select = document.getElementById('midiInputSelect');
1005→  if (!navigator.requestMIDIAccess) {
1006→    updateMidiStatus('Web MIDI not supported');
1007→    select.innerHTML = '<option value="">Web MIDI unavailable</option>';
1008→    return;
1009→  }
1010→
1011→  try {
1012→    updateMidiStatus('Checking MIDI devices...');
1013→    if (!midiAccess) {
1014→      midiAccess = await navigator.requestMIDIAccess();
1015→      midiAccess.onstatechange = function() { refreshMidiInputs(); };
1016→    }
1017→
1018→    var inputs = Array.from(midiAccess.inputs.values());
1019→    select.innerHTML = '';
1020→    if (!inputs.length) {
1021→      select.innerHTML = '<option value="">No MIDI input found</option>';
1022→      if (midiInput) midiInput.onmidimessage = null;
1023→      midiInput = null;
1024→      updateMidiStatus('No MIDI input found');
1025→      return;
1026→    }
1027→
1028→    inputs.forEach(function(input) {
1029→      var option = document.createElement('option');
1030→      option.value = input.id;
1031→      option.textContent = input.name || 'MIDI Input';
1032→      select.appendChild(option);
1033→    });
1034→
1035→    if (!midiInput || !midiAccess.inputs.has(midiInput.id)) {
1036→      setMidiInput(inputs[0].id);
1037→    } else {
1038→      select.value = midiInput.id;
1039→      updateMidiStatus('MIDI: ' + (midiInput.name || 'Connected'));
1040→    }
1041→  } catch (err) {
1042→    var name = err && err.name ? err.name : 'Error';
1043→    if (name === 'NotAllowedError' || name === 'SecurityError') {
1044→      updateMidiStatus('MIDI permission blocked');
1045→    } else {
1046→      updateMidiStatus('MIDI error: ' + name);
1047→    }
1048→    console.error('Failed to refresh MIDI inputs', err);
1049→  }
1050→}
