1052→function setMidiInput(inputId) {
1053→  if (!midiAccess) return;
1054→  if (midiInput) midiInput.onmidimessage = null;
1055→  midiInput = inputId ? midiAccess.inputs.get(inputId) : null;
1056→  if (midiInput) {
1057→    midiInput.onmidimessage = handleMidiMessage;
1058→    document.getElementById('midiInputSelect').value = midiInput.id;
1059→    updateMidiStatus('MIDI: ' + (midiInput.name || 'Connected'));
1060→  } else {
1061→    updateMidiStatus('MIDI not connected');
1062→  }
1063→}
