1065→function handleMidiMessage(event) {
1066→  var data = event.data;
1067→  if (!data || data.length < 2) return;
1068→
1069→  var status = data[0];
1070→  var command = status & 0xf0;
1071→  var channel = status & 0x0f;
1072→  var data1 = data[1];
1073→  var data2 = data.length > 2 ? data[2] : 0;
1074→  var nowMs = Date.now();
1075→
1076→  if (command === 0x90 && data2 > 0) {
1077→    handleNoteOn(data1, data2, nowMs);
1078→    sendMidiEvent({ event: 'noteOn', note: data1, velocity: data2, channel: channel, timestampMs: nowMs });
1079→  } else if (command === 0x80 || (command === 0x90 && data2 === 0)) {
1080→    handleNoteOff(data1, nowMs);
1081→    sendMidiEvent({ event: 'noteOff', note: data1, velocity: data2, channel: channel, timestampMs: nowMs });
1082→  } else if (command === 0xb0) {
1083→    handleControlChange(data1, data2, nowMs);
1084→    sendMidiEvent({ event: 'controlChange', controller: data1, value: data2, channel: channel, timestampMs: nowMs });
1085→  }
1086→}
1087→
1088→function handleNoteOn(note, velocity, nowMs) {
1089→  // Close any open history entries for this note (e.g. pedal-sustained re-trigger)
1090→  for (var hi = noteHistory.length - 1; hi >= 0; hi--) {
1091→    if (noteHistory[hi].note === note && noteHistory[hi].endMs === 0) {
1092→      noteHistory[hi].endMs = nowMs;
1093→      if (!noteHistory[hi].fingerDurationMs) noteHistory[hi].fingerDurationMs = nowMs - noteHistory[hi].startMs;
1094→      break;
1095→    }
1096→  }
1097→  activeNotes.set(note, { note: note, velocity: velocity, timestamp: nowMs });
1098→  fingerDownNotes.add(note);
1099→  pedalSustainedNotes.delete(note);

